import xlrd

def sheet2json(sh):
    keys = []
    ret = []
    for i in range(0, sh.ncols):
        keys.append(sh.cell_value(rowx=0, colx=i))
    for i in range(1, sh.nrows):
        obj = {}
        for j in range(0, sh.ncols):
            try:
                obj[keys[j]] = sh.cell_value(rowx=i, colx=j)
            except:
                obj[keys[j]] = None
        ret.append(obj)
    return ret

def unzzazz(x):
    if str(x).startswith("x"):
        return int(x[1:], 16)
    if x < 1:
        return int(x*100)
    if x < 0:
        return int(256+x)
    return int(x)

def hi(x):
    return x // 256
def lo(x):
    return x % 256

